import "package:flutter/material.dart"; import "package:flutter_blurhash/flutter_blurhash.dart"; import "package:cached_network_image/cached_network_image.dart"; import "../../ui/nios_ui.dart"; class BlurHashImage extends StatelessWidget { final String imageUrl; final String? blurHash; final double? width; final double? height; final BoxFit fit; final BorderRadius? borderRadius; const BlurHashImage({super.key, required this.imageUrl, this.blurHash, this.width, this.height, this.fit = BoxFit.cover, this.borderRadius}); @override Widget build(BuildContext context) { Widget image = CachedNetworkImage(imageUrl: imageUrl, width: width, height: height, fit: fit, placeholder: (context, url) => blurHash != null ? BlurHash(hash: blurHash!, imageFit: fit) : Container(color: NiosPalette.surfaceHover, child: const Center(child: CircularProgressIndicator(strokeWidth: 2))), errorWidget: (context, url, error) => Container(color: NiosPalette.surfaceHover, child: Icon(Icons.error_outline, color: NiosPalette.textSecondary))); if (borderRadius != null) { image = ClipRRect(borderRadius: borderRadius!, child: image); } return image; } }
